import './Header.css'
import React from 'react'
import SearchIcon from '@mui/icons-material/Search';
import logo from './Robectron.png';
import { Dropdown } from 'react-bootstrap';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faPhone, faEnvelope, faMapMarker, faDollarSign, faUser } from '@fortawesome/free-solid-svg-icons';

function Header(){
    return (
        <header>
            <div id="top-header">
                <div className="container">
                    <ul className="header-links pull-left">
                        <li><a href="#"><FontAwesomeIcon icon={faPhone} /> +089-481-7366</a></li>
                        <li><a href="#"><FontAwesomeIcon icon={faEnvelope} /> info@robectron.com</a></li>
                        <li><a href="#"><FontAwesomeIcon icon={faMapMarker} /> +089-481-7366</a></li>
                    </ul>
                    <ul className="header-links pull-right">
                        <li><a href="#"><FontAwesomeIcon icon={faDollarSign} /> +089-481-7366</a></li>
                        <li><a href="#"><FontAwesomeIcon icon={faUser} /> info@robectron.com</a></li>
                    </ul>
                </div>
            </div>

            <div id="header">
                <div className="container">
                    <div className="row">
                        <div className="col-md-3">
                            <div className="header-logo">
                                <a href="#" className="logo">
                                    <img src={logo} alt="" width="180" height="75" />
                                </a>
                            </div>
                        </div>
                        {/* {SEARCH BAR} */}
                        <div className="col-md-6">
                            <div className="header-search">
                                <form>
                                    <select className="input-select">
                                        <option value="0">All Categories</option>
                                        <option value="1">Category 01</option>
                                        <option value="1">Category 02</option>
                                    </select>
                                    <input className="input" placeholder="Search here" />
                                    <button className="search-btn">Search</button>
                                </form>
                            </div>
                        </div>
                        {/* {ACCOUNT} */}
                        <div className="col-md-3 clearfix">
                            <div className="header-ctn">
                                {/* WISHLIST */}
                                <div>
                                    <a href="#">
                                        <i className="fa fa-heart-o"></i>
                                        <span>Your Wishlist</span>
                                        <div className="qty">2</div>
                                    </a>
                                </div>
                               {/* CART */}
                                <div className="dropdown">
                                    <a className="dropdown-toggle" data-toggle="dropdown" aria-expanded="true">
                                        <i className="fa fa-shopping-cart"></i>
                                        <span>Your Cart</span>
                                        <div className="qty">3</div>
                                    </a>
                                    <div class="cart-dropdown">
										<div class="cart-list">
											<div class="product-widget">
												<div class="product-img">
													<img src="./img/product01.png" alt=""/>
												</div>
												<div class="product-body">
													<h3 class="product-name"><a href="#">product name goes here</a></h3>
													<h4 class="product-price"><span class="qty">1x</span>$980.00</h4>
												</div>
												<button class="delete"><i class="fa fa-close"></i></button>
											</div>

											<div class="product-widget">
												<div class="product-img">
													<img src="./img/product02.png" alt=""/>
												</div>
												<div class="product-body">
													<h3 class="product-name"><a href="#">product name goes here</a></h3>
													<h4 class="product-price"><span class="qty">3x</span>$980.00</h4>
												</div>
												<button class="delete"><i class="fa fa-close"></i></button>
											</div>
										</div>
										<div class="cart-summary">
											<small>3 Item(s) selected</small>
